/**
 * Auth Context
 * Provides global authentication state and actions
 */

import React, {
  createContext,
  useContext,
  useState,
  useEffect,
  useCallback,
} from "react";
import { authAPI } from "../services/api";
import toast from "react-hot-toast";

const AuthContext = createContext(null);

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  // ============================================================
  // Initialize auth on app load (SAFE VERSION)
  // ============================================================
  useEffect(() => {
    let isMounted = true;

    const token = localStorage.getItem("taskflow_token");
    const savedUser = localStorage.getItem("taskflow_user");

    // No token → stop loading immediately
    if (!token) {
      setLoading(false);
      return;
    }

    // Restore cached user (instant UI)
    if (savedUser) {
      try {
        if (isMounted) {
          setUser(JSON.parse(savedUser));
        }
      } catch {
        localStorage.removeItem("taskflow_user");
      }
    }

    // Verify token with backend
    authAPI
      .getMe()
      .then(({ data }) => {
        if (isMounted) {
          setUser(data.user);
          localStorage.setItem(
            "taskflow_user",
            JSON.stringify(data.user)
          );
        }
      })
      .catch(() => {
        // Silent cleanup (NO TOAST HERE)
        if (isMounted) {
          setUser(null);
          localStorage.removeItem("taskflow_user");
          localStorage.removeItem("taskflow_token");
        }
      })
      .finally(() => {
        if (isMounted) setLoading(false);
      });

    return () => {
      isMounted = false;
    };
  }, []);

  // ============================================================
  // Register
  // ============================================================
  const register = useCallback(async (formData) => {
    const { data } = await authAPI.register(formData);

    localStorage.setItem("taskflow_token", data.token);
    localStorage.setItem("taskflow_user", JSON.stringify(data.user));

    setUser(data.user);

    toast.success(`Welcome to TaskFlow, ${data.user.name}! 🎉`);

    return data;
  }, []);

  // ============================================================
  // Login
  // ============================================================
  const login = useCallback(async (credentials) => {
    const { data } = await authAPI.login(credentials);

    localStorage.setItem("taskflow_token", data.token);
    localStorage.setItem("taskflow_user", JSON.stringify(data.user));

    setUser(data.user);

    toast.success(`Welcome back, ${data.user.name}!`);

    return data;
  }, []);

  // ============================================================
  // Logout (clean + silent safe reset)
  // ============================================================
  const logout = useCallback(() => {
    localStorage.removeItem("taskflow_token");
    localStorage.removeItem("taskflow_user");

    setUser(null);

    toast.success("Logged out successfully");
  }, []);

  // ============================================================
  // Update user profile
  // ============================================================
  const updateUser = useCallback((updatedUser) => {
    setUser(updatedUser);
    localStorage.setItem(
      "taskflow_user",
      JSON.stringify(updatedUser)
    );
  }, []);

  return (
    <AuthContext.Provider
      value={{ user, loading, register, login, logout, updateUser }}
    >
      {children}
    </AuthContext.Provider>
  );
};

// ============================================================
// Hook
// ============================================================
export const useAuth = () => {
  const ctx = useContext(AuthContext);

  if (!ctx) {
    throw new Error("useAuth must be used within AuthProvider");
  }

  return ctx;
};
